def solve(points, k):
    n = len(points)
    best = None
    for i in range(n):
        xi, yi = points[i]
        for j in range(i + 1, n):
            xj, yj = points[j]
            if xj - xi > k:
                break
            val = yi + yj + (xj - xi)
            if best is None or val > best:
                best = val
    return best


class Solution:
    def findMaxValueOfEquation(self, points, k):
        return solve(points, k)

