from collections import deque


class Solution:
    def findMaxValueOfEquation(self, points: List[List[int]], k: int) -> int:
        dq = deque()
        best = None
        for x, y in points:
            while dq and x - dq[0][0] > k:
                dq.popleft()
            if dq:
                cand = x + y + dq[0][1]
                if best is None or cand > best:
                    best = cand
            v = y - x
            while dq and dq[-1][1] <= v:
                dq.pop()
            dq.append((x, v))
        return best

