var findMaxValueOfEquation = function(points, k) {
    const dqX = [];
    const dqV = [];
    let start = 0;
    let best = null;
    for (const [x, y] of points) {
        while (start < dqX.length && x - dqX[start] > k) start++;
        if (start < dqX.length) {
            const cand = x + y + dqV[start];
            if (best === null || cand > best) best = cand;
        }
        const v = y - x;
        while (dqX.length > start && dqV[dqX.length - 1] <= v) {
            dqX.pop();
            dqV.pop();
        }
        dqX.push(x);
        dqV.push(v);
    }
    return best;
};
